function UnitDetail({ property, unit }) {
  const { div, h1, h2, p, span, dl, dt, dd } = tags;
  const [activeTab, setActiveTab] = createSignal('payments');
  const statusColor = unit.status === 'occupied' ? 'success' : 'danger';

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _aic _gap2 _mb2') },
      link({ href: `/properties/${property.id}`, class: css('_fgmuted _hoverFg') }, icon('arrow-left'), ` ${property.name || property.address}`)
    ),
    div({ class: css('_flex _jcsb _aic') },
      div({},
        div({ class: css('_flex _aic _gap3') },
          h1({ class: css('_heading2') }, `Unit ${unit.number}`),
          Badge({ variant: statusColor }, unit.status)
        ),
        p({ class: css('_fgmuted') }, property.address)
      ),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline' }, icon('edit'), 'Edit Unit'),
        unit.status === 'vacant' ?
          Button({ variant: 'primary' }, icon('user-plus'), 'Add Tenant') :
          Button({ variant: 'outline' }, icon('refresh-cw'), 'Renew Lease')
      )
    ),
    div({ class: css('_grid _cols2 _gap6') },
      div({ class: css('estate-card _p4') },
        h2({ class: css('_heading5 _mb4') }, 'Unit Specs'),
        dl({ class: css('_grid _cols2 _gap3') },
          dt({ class: css('_textsm _fgmuted') }, 'Bedrooms'),
          dd({ class: css('_font500') }, unit.beds),
          dt({ class: css('_textsm _fgmuted') }, 'Bathrooms'),
          dd({ class: css('_font500') }, unit.baths),
          dt({ class: css('_textsm _fgmuted') }, 'Square Feet'),
          dd({ class: css('_font500') }, unit.sqft.toLocaleString()),
          dt({ class: css('_textsm _fgmuted') }, 'Floor'),
          dd({ class: css('_font500') }, unit.floor || '—'),
          dt({ class: css('_textsm _fgmuted') }, 'Monthly Rent'),
          dd({ class: css('_font500') }, `$${unit.rent.toLocaleString()}`)
        ),
        unit.amenities?.length > 0 ? div({ class: css('_mt4 _pt4 _borderT') },
          span({ class: css('_textsm _fgmuted _block _mb2') }, 'Amenities'),
          div({ class: css('_flex _flexwrap _gap2') },
            ...unit.amenities.map(a => Badge({ variant: 'outline' }, a))
          )
        ) : null
      ),
      unit.tenant ? div({ class: css('estate-card _p4') },
        h2({ class: css('_heading5 _mb4') }, 'Current Tenant'),
        TenantCard({ tenant: unit.tenant, preset: 'compact' }),
        div({ class: css('_mt4 _pt4 _borderT') },
          h2({ class: css('_heading6 _mb3') }, 'Lease Details'),
          dl({ class: css('_grid _cols2 _gap3') },
            dt({ class: css('_textsm _fgmuted') }, 'Lease Start'),
            dd({ class: css('_font500') }, unit.leaseStart),
            dt({ class: css('_textsm _fgmuted') }, 'Lease End'),
            dd({ class: css('_font500') }, unit.leaseEnd),
            dt({ class: css('_textsm _fgmuted') }, 'Security Deposit'),
            dd({ class: css('_font500') }, `$${unit.deposit?.toLocaleString() || '—'}`)
          )
        )
      ) : div({ class: css('estate-card _p4 _flex _col _aic _jcc _h48') },
        icon('home', { class: css('_fgmuted _mb2'), size: '32' }),
        span({ class: css('_fgmuted _mb4') }, 'Unit is vacant'),
        Button({ variant: 'primary' }, icon('user-plus'), 'Add Tenant')
      )
    ),
    Tabs({ value: activeTab(), onValueChange: setActiveTab },
      Tabs.List({},
        Tabs.Trigger({ value: 'payments' }, 'Payment History'),
        Tabs.Trigger({ value: 'maintenance' }, 'Maintenance'),
        Tabs.Trigger({ value: 'documents' }, 'Documents')
      ),
      Tabs.Content({ value: 'payments' }, PaymentHistory({ unitId: unit.id })),
      Tabs.Content({ value: 'maintenance' }, UnitMaintenance({ unitId: unit.id })),
      Tabs.Content({ value: 'documents' }, UnitDocuments({ unitId: unit.id }))
    )
  );
}

